import React, { useState } from 'react';
import { Shield, User, Stethoscope, Eye, EyeOff } from 'lucide-react';
import { API_BASE_URL } from './config';

const Login = () => {
  const [selectedRole, setSelectedRole] = useState('patient');
  const [email, setEmail] = useState('');
  const [password, setPassword] = useState('');
  const [error, setError] = useState<string | null>(null);
  const [showPassword, setShowPassword] = useState(false);
  const [isLoading, setIsLoading] = useState(false);

  const roles = [
    { id: 'admin', label: 'Admin', icon: Shield, gradient: 'from-purple-500 to-pink-500' },
    { id: 'patient', label: 'Patient', icon: User, gradient: 'from-emerald-500 to-teal-500' },
    { id: 'doctor', label: 'Doctor', icon: Stethoscope, gradient: 'from-cyan-500 to-blue-500' },
  ];

  const handleSubmit = async (e: React.FormEvent) => {
    e.preventDefault();
    setIsLoading(true);
    setError(null);

    try {
      const response = await fetch(`${API_BASE_URL}/api/login`, {
        method: 'POST',
        headers: {
          'Content-Type': 'application/json',
        },
        body: JSON.stringify({ email, password, role: selectedRole }),
      });

      if (response.ok) {
        const data = await response.json();
        localStorage.setItem('token', data.token);
        localStorage.setItem('userRole', data.role);
        localStorage.setItem('userEmail', email);

        console.log(`Redirecting to ${data.role} dashboard...`);
      } else {
        const errorData = await response.json();
        setError(errorData.error || 'Login failed');
      }
    } catch (error) {
      setError('An error occurred. Please try again.');
    } finally {
      setIsLoading(false);
    }
  };

  const selectedRoleData = roles.find((r) => r.id === selectedRole);

  return (
    <div className="min-h-screen bg-gradient-to-br from-slate-50 via-blue-50 to-purple-50 flex items-center justify-center p-4 sm:p-6 lg:p-8">
      <div className="absolute inset-0 overflow-hidden pointer-events-none">
        <div className="absolute top-1/4 -left-20 w-96 h-96 bg-gradient-to-r from-emerald-400/30 to-teal-400/30 rounded-full blur-3xl animate-pulse"></div>
        <div className="absolute bottom-1/4 -right-20 w-96 h-96 bg-gradient-to-r from-purple-400/30 to-pink-400/30 rounded-full blur-3xl animate-pulse" style={{ animationDelay: '1s' }}></div>
      </div>

      <div className="w-full max-w-md relative animate-fadeIn">
        <div className="bg-white/80 backdrop-blur-xl rounded-2xl shadow-2xl overflow-hidden transform transition-all duration-300 hover:shadow-3xl border border-white/20">
          <div className={`bg-gradient-to-r ${selectedRoleData?.gradient} p-8 text-white relative overflow-hidden transition-all duration-500`}>
            <div className="absolute inset-0 bg-black/10"></div>
            <div className="relative z-10">
              <div className="flex justify-center mb-4">
                <div className="bg-white/20 backdrop-blur-sm p-4 rounded-full transform transition-transform duration-300 hover:scale-110 hover:rotate-12">
                  {selectedRoleData && <selectedRoleData.icon size={40} className="animate-pulse" />}
                </div>
              </div>
              <h2 className="text-3xl font-bold text-center mb-2 animate-slideDown">Welcome Back</h2>
              <p className="text-center text-white/90 text-sm animate-slideDown" style={{ animationDelay: '0.1s' }}>
                Sign in to your {selectedRoleData?.label} account
              </p>
            </div>
          </div>

          <div className="p-6 sm:p-8">
            <div className="grid grid-cols-3 gap-2 mb-8">
              {roles.map((role, index) => (
                <button
                  key={role.id}
                  onClick={() => setSelectedRole(role.id)}
                  className={`relative flex flex-col items-center justify-center gap-2 py-3 sm:py-4 rounded-xl transition-all duration-300 transform hover:scale-105 group animate-slideUp`}
                  style={{ animationDelay: `${index * 0.1}s` }}
                >
                  <div className={`absolute inset-0 bg-gradient-to-r ${role.gradient} rounded-xl transition-opacity duration-300 ${
                    selectedRole === role.id ? 'opacity-100' : 'opacity-0 group-hover:opacity-10'
                  }`}></div>
                  <div className={`relative transition-all duration-300 ${
                    selectedRole === role.id ? 'text-white' : 'text-gray-600 group-hover:text-gray-800'
                  }`}>
                    <role.icon size={20} className={`transition-transform duration-300 ${selectedRole === role.id ? 'scale-110' : ''}`} />
                  </div>
                  <span className={`relative text-xs font-medium transition-all duration-300 ${
                    selectedRole === role.id ? 'text-white' : 'text-gray-600 group-hover:text-gray-800'
                  }`}>
                    {role.label}
                  </span>
                </button>
              ))}
            </div>

            <form onSubmit={handleSubmit} className="space-y-5">
              <div className="animate-slideUp" style={{ animationDelay: '0.3s' }}>
                <label htmlFor="email" className="block text-sm font-semibold text-gray-700 mb-2">
                  Email Address
                </label>
                <input
                  id="email"
                  type="email"
                  value={email}
                  onChange={(e) => setEmail(e.target.value)}
                  placeholder="you@example.com"
                  className="w-full px-4 py-3 border-2 border-gray-200 rounded-xl focus:outline-none focus:border-transparent focus:ring-2 focus:ring-offset-0 transition-all duration-300 bg-gray-50 hover:bg-white focus:bg-white"
                  style={{
                    focusRing: selectedRoleData?.gradient
                  }}
                  required
                />
              </div>

              <div className="animate-slideUp" style={{ animationDelay: '0.4s' }}>
                <label htmlFor="password" className="block text-sm font-semibold text-gray-700 mb-2">
                  Password
                </label>
                <div className="relative">
                  <input
                    id="password"
                    type={showPassword ? "text" : "password"}
                    value={password}
                    onChange={(e) => setPassword(e.target.value)}
                    placeholder="Enter your password"
                    className="w-full px-4 py-3 pr-12 border-2 border-gray-200 rounded-xl focus:outline-none focus:border-transparent focus:ring-2 focus:ring-offset-0 transition-all duration-300 bg-gray-50 hover:bg-white focus:bg-white"
                    required
                  />
                  <button
                    type="button"
                    className="absolute inset-y-0 right-0 pr-4 flex items-center transition-transform duration-200 hover:scale-110"
                    onClick={() => setShowPassword(!showPassword)}
                  >
                    {showPassword ? (
                      <EyeOff className="h-5 w-5 text-gray-400 hover:text-gray-600" />
                    ) : (
                      <Eye className="h-5 w-5 text-gray-400 hover:text-gray-600" />
                    )}
                  </button>
                </div>
              </div>

              {error && (
                <div className="bg-red-50 border-l-4 border-red-500 p-4 rounded-lg animate-shake">
                  <p className="text-red-700 text-sm font-medium">{error}</p>
                </div>
              )}

              <button
                type="submit"
                disabled={isLoading}
                className={`w-full bg-gradient-to-r ${selectedRoleData?.gradient} text-white py-3.5 rounded-xl font-semibold transition-all duration-300 transform hover:scale-[1.02] hover:shadow-lg active:scale-[0.98] disabled:opacity-50 disabled:cursor-not-allowed relative overflow-hidden group animate-slideUp`}
                style={{ animationDelay: '0.5s' }}
              >
                <span className="absolute inset-0 bg-white/20 transform -skew-x-12 -translate-x-full group-hover:translate-x-full transition-transform duration-700 ease-in-out"></span>
                <span className="relative flex items-center justify-center gap-2">
                  {isLoading ? (
                    <>
                      <div className="w-5 h-5 border-2 border-white/30 border-t-white rounded-full animate-spin"></div>
                      Signing in...
                    </>
                  ) : (
                    <>
                      <selectedRoleData.icon size={18} />
                      Login as {selectedRoleData?.label}
                    </>
                  )}
                </span>
              </button>

              <div className="text-center animate-slideUp" style={{ animationDelay: '0.6s' }}>
                <button type="button" className="text-sm text-gray-600 hover:text-gray-800 font-medium transition-colors duration-200 hover:underline">
                  Forgot your password?
                </button>
              </div>
            </form>
          </div>

          <div className="bg-gradient-to-r from-gray-50 to-slate-50 px-6 sm:px-8 py-5 border-t border-gray-100">
            <p className="text-sm text-center text-gray-600">
              Don't have an account?{' '}
              <button
                onClick={() => console.log('Navigate to signup')}
                className="font-bold bg-gradient-to-r from-emerald-600 to-teal-600 bg-clip-text text-transparent hover:from-emerald-700 hover:to-teal-700 transition-all duration-300 hover:underline"
              >
                Sign up now
              </button>
            </p>
          </div>
        </div>

        <div className="mt-8 text-center animate-slideUp" style={{ animationDelay: '0.7s' }}>
          <p className="text-sm text-gray-600">
            Protected by enterprise-grade security
          </p>
        </div>
      </div>
    </div>
  );
};

export default Login;
